class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        m = len(str(k))
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            for l in range(1, m + 1):
                if i - l < 0:
                    continue
                substr = s[i-l:i]
                if len(substr) > 1 and substr[0] == '0':
                    continue
                if int(substr) > k:
                    continue
                dp[i] = (dp[i] + dp[i - l]) % MOD
        return dp[n] % MOD

